-- Test plan:
-- 1. Seed 1 lister, 1 creator, 1 listing (active) with initial version, 1 pending application.
-- 2. UPDATE listings SET price_cents ... -> verify: new listing_versions row, application cascaded, notification emitted, current_version_id swapped.
-- 3. UPDATE listings SET title ... -> verify: NO bump (title is not versioned).
-- 4. UPDATE listings SET status='paused' -> verify: NO bump on status-only edit.
-- 5. request_listing_version_bump(lid, 'conditions') on active listing -> verify: bump fires with changed_fields including 'conditions'; version_bump_reason remains null on disk.
-- 6. request_listing_version_bump(lid, 'bogus') -> raises exception.
begin;
create temp table _asserts (label text, actual text, expected text, ok boolean) on commit drop;

do $$
declare
  v_lister_id    uuid := gen_random_uuid();
  v_creator_id   uuid := gen_random_uuid();
  v_listing_id   uuid := gen_random_uuid();
  v_v1_id        uuid := gen_random_uuid();
  v_app_id       uuid := gen_random_uuid();
  v_version_count integer;
  v_app_status    public.application_status;
  v_notif_count   integer;
  v_notif_payload jsonb;
  v_current_ver   uuid;
  v_version_num   integer;
  v_returned_ver  uuid;
  v_reason_left   text;
  v_exception_caught boolean := false;
begin
  insert into public.users(id, role, username) values
    (v_lister_id,  'lister',  'us010_lister_' || substr(v_lister_id::text,1,8)),
    (v_creator_id, 'creator', 'us010_creator_' || substr(v_creator_id::text,1,8));
  insert into public.lister_profiles(user_id, email, org_name) values (v_lister_id, 'us010_lister@example.com', 'US-010 Co');
  insert into public.creator_profiles(user_id) values (v_creator_id);

  -- Listing starts as draft
  insert into public.listings(id, lister_id, status, title, price_cents, version_number)
    values (v_listing_id, v_lister_id, 'draft', 'US-010 Test Listing', 1000, 1);

  -- Initial listing_versions row
  insert into public.listing_versions(id, listing_id, version_number, price_cents, currency, max_submissions, snapshot, changed_fields)
    values (v_v1_id, v_listing_id, 1, 1000, 'USD', null, '{}'::jsonb, '{}'::text[]);

  -- Attach current_version_id -> listing_versions row. Trigger runs but
  -- no scalar diff + no cue + status still draft => no bump.
  update public.listings set current_version_id = v_v1_id where id = v_listing_id;

  -- Flip to active. Trigger runs, no scalar diff, no cue => no bump.
  update public.listings set status = 'active' where id = v_listing_id;

  -- Sanity: still at version 1, no new versions row, no notifications.
  select count(*) into v_version_count from public.listing_versions where listing_id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('after activation: listing_versions count',
     v_version_count::text, '1', v_version_count = 1);

  -- Insert a pending application against v1.
  insert into public.applications(id, listing_id, listing_version_id, creator_id, status)
    values (v_app_id, v_listing_id, v_v1_id, v_creator_id, 'pending');

  -- ========= TEST 1: scalar price bump =========
  update public.listings set price_cents = 2000 where id = v_listing_id;

  select count(*) into v_version_count from public.listing_versions where listing_id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('price bump: listing_versions count',
     v_version_count::text, '2', v_version_count = 2);

  select current_version_id, version_number into v_current_ver, v_version_num
    from public.listings where id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('price bump: version_number', v_version_num::text, '2', v_version_num = 2),
    ('price bump: current_version_id swapped',
     (v_current_ver <> v_v1_id)::text, 'true', v_current_ver <> v_v1_id);

  select status into v_app_status from public.applications where id = v_app_id;
  insert into _asserts(label, actual, expected, ok) values
    ('price bump: application cascaded',
     v_app_status::text, 'cancelled_listing_edit',
     v_app_status = 'cancelled_listing_edit');

  select count(*), (array_agg(payload))[1]
    into v_notif_count, v_notif_payload
    from public.notifications
   where user_id = v_creator_id and kind = 'listing_version_changed';
  insert into _asserts(label, actual, expected, ok) values
    ('price bump: notification count', v_notif_count::text, '1', v_notif_count = 1),
    ('price bump: notification changed_fields',
     (v_notif_payload->'changed_fields')::text, '["price_cents"]',
     (v_notif_payload->'changed_fields') = '["price_cents"]'::jsonb),
    ('price bump: notification listing_id',
     (v_notif_payload->>'listing_id'), v_listing_id::text,
     (v_notif_payload->>'listing_id') = v_listing_id::text),
    ('price bump: notification new_version',
     (v_notif_payload->>'new_version'), '2',
     (v_notif_payload->>'new_version') = '2'),
    ('price bump: notification previous_version_id',
     (v_notif_payload->>'previous_version_id'), v_v1_id::text,
     (v_notif_payload->>'previous_version_id') = v_v1_id::text);

  -- ========= TEST 2: title-only edit must NOT bump =========
  update public.listings set title = 'Renamed Listing' where id = v_listing_id;
  select count(*) into v_version_count from public.listing_versions where listing_id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('title-only edit: version count unchanged',
     v_version_count::text, '2', v_version_count = 2);

  -- ========= TEST 3: status-only change must NOT bump =========
  update public.listings set status = 'paused' where id = v_listing_id;
  select count(*) into v_version_count from public.listing_versions where listing_id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('status=paused edit: version count unchanged',
     v_version_count::text, '2', v_version_count = 2);

  -- Flip back to active for subsequent tests.
  update public.listings set status = 'active' where id = v_listing_id;

  -- ========= TEST 4: request_listing_version_bump('conditions') =========
  -- Seed a fresh pending application to verify cascade still fires on cue-only bumps.
  insert into public.applications(listing_id, listing_version_id, creator_id, status)
    values (v_listing_id, v_current_ver, v_creator_id, 'pending');

  v_returned_ver := app_private.request_listing_version_bump(v_listing_id, 'conditions');

  select count(*) into v_version_count from public.listing_versions where listing_id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('cue conditions: version count incremented',
     v_version_count::text, '3', v_version_count = 3);

  select current_version_id, version_number into v_current_ver, v_version_num
    from public.listings where id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('cue conditions: version_number now 3',
     v_version_num::text, '3', v_version_num = 3);

  -- version_bump_reason must have been consumed (NULL on disk).
  select version_bump_reason into v_reason_left from public.listings where id = v_listing_id;
  insert into _asserts(label, actual, expected, ok) values
    ('cue conditions: version_bump_reason consumed',
     coalesce(v_reason_left, '<null>'), '<null>', v_reason_left is null);

  -- Newly created pending app cascaded.
  select count(*) into v_notif_count
    from public.applications
   where listing_id = v_listing_id and status = 'pending';
  insert into _asserts(label, actual, expected, ok) values
    ('cue conditions: no pending apps remain',
     v_notif_count::text, '0', v_notif_count = 0);

  -- Latest version's changed_fields contains 'conditions'.
  select changed_fields::text into v_reason_left
    from public.listing_versions
   where listing_id = v_listing_id
   order by version_number desc limit 1;
  insert into _asserts(label, actual, expected, ok) values
    ('cue conditions: listing_versions.changed_fields',
     v_reason_left, '{conditions}', v_reason_left = '{conditions}');

  -- ========= TEST 5: invalid reason raises =========
  begin
    perform app_private.request_listing_version_bump(v_listing_id, 'bogus_reason');
  exception when others then
    v_exception_caught := true;
  end;
  insert into _asserts(label, actual, expected, ok) values
    ('invalid reason raises',
     v_exception_caught::text, 'true', v_exception_caught);
end $$;

